(function(){"use strict";var PERIODS={all:{eyebrow:"All-time champions",sub:"The games that defined the platform."},year:{eyebrow:"Top of this year",sub:"Year-to-date leaderboard."},month:{eyebrow:"This month's best",sub:"The current month's top games."}};var currentPeriod="all";var currentGenre="";var inited=false;var cache={all:null,year:null,month:null};var loading=false;var modal,closeBtn,podiumEl,listEl,filteredEmptyEl;var segmentEl,genreGroupEl,eyebrowEl,subEl;var railBtn;function base(){return typeof BASE_URL!=="undefined"?BASE_URL:"/"}function formatPlays(n){n=n||0;if(n>=1e7)return(n/1e6).toFixed(1).replace(/\.0$/,"")+"M";if(n>=1e6)return(n/1e6).toFixed(1)+"M";if(n>=1e3)return Math.round(n/1e3)+"K";return n.toString()}function formatPlaysExact(n){return(n||0).toLocaleString()}function formatTotal(n){n=n||0;if(n>=1e9)return(n/1e9).toFixed(1)+"B";if(n>=1e6)return(n/1e6).toFixed(1)+"M";return n.toLocaleString()}function totalPlays(games){return games.reduce(function(s,g){return s+(g.plays||0)},0)}function esc(s){return String(s==null?"":s).replace(/[&<>"]/g,function(c){return{"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;"}[c]})}function rankedGames(){var pool=cache[currentPeriod]||[];if(currentGenre){pool=pool.filter(function(g){return(g.category||"")===currentGenre})}return pool}function buildMovement(mv){if(mv==null)return"";if(mv==="NEW")return'<span class="played-movement new">NEW</span>';if(mv===0){return'<span class="played-movement flat" aria-label="Held position"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round"><path d="M5 12h14"/></svg></span>'}if(mv>0){return'<span class="played-movement up" aria-label="Climbed '+mv+' positions"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M6 15l6-6 6 6"/></svg>'+Math.abs(mv)+"</span>"}return'<span class="played-movement down" aria-label="Dropped '+Math.abs(mv)+' positions"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="3" stroke-linecap="round" stroke-linejoin="round"><path d="M6 9l6 6 6-6"/></svg>'+Math.abs(mv)+"</span>"}function artStyle(g){var color=g.color||"#4a5cf0";if(g.image)return"background:url('"+g.image+"') center/cover, "+color;return"background:"+color}function go(url){if(url)window.location.href=url}function renderHero(games){var p=PERIODS[currentPeriod];eyebrowEl.textContent=p.eyebrow;var topTotal=totalPlays(games.slice(0,20));var topNote=games.length>=20?"<strong>"+formatTotal(topTotal)+" plays</strong> across the top 20 games.":"<strong>"+formatTotal(topTotal)+" plays</strong> across "+games.length+" games.";subEl.innerHTML=p.sub+" "+topNote}function renderPodium(games){if(!podiumEl)return;while(podiumEl.firstChild)podiumEl.removeChild(podiumEl.firstChild);if(games.length===0)return;var spots=[{game:games[1],rank:2,medal:"silver",emoji:"\u{1F948}",label:"#2"},{game:games[0],rank:1,medal:"gold",emoji:"\u{1F947}",label:"#1"},{game:games[2],rank:3,medal:"bronze",emoji:"\u{1F949}",label:"#3"}];spots.forEach(function(spot){if(!spot.game){var placeholder=document.createElement("div");placeholder.style.opacity="0";podiumEl.appendChild(placeholder);return}var g=spot.game;var playsDisplay=spot.rank===1?formatPlaysExact(g.plays):formatPlays(g.plays);var eyebrowExtra=spot.rank===1?'<div class="podium-eyebrow">Reigning Champion</div>':"";var step=document.createElement("div");step.className="podium-step "+spot.medal;step.setAttribute("tabindex","0");step.setAttribute("role","group");step.setAttribute("aria-label",spot.label+": "+g.name+" - "+formatPlays(g.plays)+" plays");if(g.preview)step.setAttribute("data-preview",encodeURIComponent(g.preview));step.innerHTML='<div class="podium-art" style="'+artStyle(g)+'"></div>'+eyebrowExtra+'<div class="podium-medal"><span class="emoji">'+spot.emoji+"</span>"+spot.label+'</div><div class="podium-info"><h4>'+esc(g.name)+'</h4><div class="meta">'+(g.category?"<span>"+esc(g.category)+"</span>":"")+'</div><div class="podium-plays">'+playsDisplay+'</div><div class="podium-plays-label">'+(currentPeriod==="all"?"Total plays":"Plays this "+currentPeriod)+"</div></div>";step.addEventListener("click",function(){go(g.url)});step.addEventListener("keydown",function(e){if(e.key==="Enter"||e.key===" "){e.preventDefault();go(g.url)}});podiumEl.appendChild(step)})}function getTierLabel(plays){if(plays>=1e7)return"Over 10M plays";if(plays>=5e6)return"Over 5M plays";if(plays>=1e6)return"Over 1M plays";if(plays>=1e3)return"Under 1M plays";return"Most played"}function renderList(games){if(!listEl)return;while(listEl.firstChild)listEl.removeChild(listEl.firstChild);var rest=games.slice(3);if(rest.length===0)return;var topPlays=games[0]?games[0].plays||0:1;var currentTier=null;var currentSection=null;rest.forEach(function(g,i){var rank=i+4;var plays=g.plays||0;var tier=getTierLabel(plays);if(tier!==currentTier){currentTier=tier;currentSection=document.createElement("div");currentSection.className="played-list-section";var head=document.createElement("div");head.className="played-tier-head";head.innerHTML='<span class="label">'+tier+"</span>";currentSection.appendChild(head);listEl.appendChild(currentSection)}currentSection.appendChild(renderRow(g,rank,plays,topPlays))});requestAnimationFrame(function(){setTimeout(function(){var rows=listEl.querySelectorAll(".played-row");rows.forEach(function(row,idx){var w=row.getAttribute("data-bar-width");setTimeout(function(){row.style.setProperty("--bar-width",w+"%")},idx*30)})},80)})}function renderRow(g,rank,plays,topPlays){var ratio=topPlays>0?plays/topPlays*100:0;ratio=Math.min(90,ratio);var row=document.createElement("div");row.className="played-row";row.setAttribute("data-rank",rank);row.setAttribute("data-bar-width",ratio.toFixed(1));row.setAttribute("tabindex","0");row.setAttribute("role","group");row.setAttribute("aria-label","#"+rank+" "+g.name+" - "+formatPlays(plays)+" plays");if(g.preview)row.setAttribute("data-preview",encodeURIComponent(g.preview));row.style.setProperty("--bar-width","0%");var movementHtml=buildMovement(g.movement);row.innerHTML='<div class="played-bar" aria-hidden="true"></div><div class="played-rank">'+rank+'</div><div class="played-thumb" style="'+artStyle(g)+'"></div><div class="played-info"><h5>'+esc(g.name)+'</h5><div class="meta">'+(g.category?'<span class="genre">'+esc(g.category)+"</span>":"")+(movementHtml?'<span class="dot"></span>'+movementHtml:"")+'</div></div><div class="played-stats"><div class="plays">'+formatPlays(plays)+'</div><div class="plays-label">Plays</div></div>';row.addEventListener("click",function(){go(g.url)});row.addEventListener("keydown",function(e){if(e.key==="Enter"||e.key===" "){e.preventDefault();go(g.url)}});return row}function computeGenres(){var pool=cache[currentPeriod]||[];var counts={};pool.forEach(function(g){var c=g.category||"";if(!c)return;counts[c]=(counts[c]||0)+1});return Object.keys(counts).sort(function(a,b){return counts[b]-counts[a]})}function renderGenrePills(){if(!genreGroupEl)return;var existing=genreGroupEl.querySelectorAll('.played-pill[data-genre]:not([data-genre=""])');for(var i=0;i<existing.length;i++)existing[i].parentNode.removeChild(existing[i]);computeGenres().forEach(function(g){var btn=document.createElement("button");btn.className="played-pill";btn.type="button";btn.setAttribute("data-genre",g);btn.textContent=g;if(currentGenre===g)btn.classList.add("is-active");btn.addEventListener("click",function(){setGenre(g)});genreGroupEl.appendChild(btn)})}function setGenre(g){currentGenre=g;if(genreGroupEl){genreGroupEl.querySelectorAll(".played-pill").forEach(function(p){p.classList.toggle("is-active",(p.getAttribute("data-genre")||"")===g)})}render()}function setPeriod(p){if(!PERIODS[p])return;currentPeriod=p;currentGenre="";if(segmentEl){segmentEl.querySelectorAll(".played-segment-btn").forEach(function(b){b.classList.toggle("is-active",b.getAttribute("data-period")===p)})}ensureData(p,function(){renderGenrePills();render()})}function ensureData(period,cb){if(cache[period]){cb();return}loading=true;renderLoading();fetch(base()+"api/most-played?period="+encodeURIComponent(period),{credentials:"same-origin"}).then(function(r){return r.ok?r.json():null}).then(function(data){cache[period]=data&&data.games||[];loading=false;cb()}).catch(function(){cache[period]=[];loading=false;cb()})}function renderLoading(){if(podiumEl)podiumEl.innerHTML="";if(listEl)listEl.innerHTML='<div class="played-tier-head"><span class="label">Loading\u2026</span></div>';if(filteredEmptyEl){filteredEmptyEl.classList.remove("is-visible");filteredEmptyEl.setAttribute("aria-hidden","true")}}function render(){if(loading){renderLoading();return}var games=rankedGames();renderHero(games);renderPodium(games);renderList(games);if(games.length===0){filteredEmptyEl.classList.add("is-visible");filteredEmptyEl.setAttribute("aria-hidden","false")}else{filteredEmptyEl.classList.remove("is-visible");filteredEmptyEl.setAttribute("aria-hidden","true")}}function openModal(){if(!inited)init();if(!modal)return;ensureData(currentPeriod,function(){renderGenrePills();render()});requestAnimationFrame(function(){modal.classList.add("is-open");modal.setAttribute("aria-hidden","false");document.body.style.overflow="hidden"})}function closeModal(){if(!modal)return;modal.classList.remove("is-open");modal.setAttribute("aria-hidden","true");document.body.style.overflow=""}function init(){if(inited)return;modal=document.getElementById("mostPlayedModal");if(!modal)return;closeBtn=document.getElementById("playedCloseBtn");podiumEl=document.getElementById("playedPodium");listEl=document.getElementById("playedList");filteredEmptyEl=document.getElementById("playedFilteredEmpty");segmentEl=document.getElementById("playedSegment");genreGroupEl=document.getElementById("playedGenreGroup");eyebrowEl=document.getElementById("playedEyebrow");subEl=document.getElementById("playedSub");railBtn=document.getElementById("playedRailBtn");if(closeBtn)closeBtn.addEventListener("click",closeModal);if(railBtn){railBtn.addEventListener("click",function(e){e.preventDefault();openModal()})}if(segmentEl){segmentEl.querySelectorAll(".played-segment-btn").forEach(function(b){b.addEventListener("click",function(){setPeriod(b.getAttribute("data-period"))})})}var allPill=genreGroupEl?genreGroupEl.querySelector('.played-pill[data-genre=""]'):null;if(allPill)allPill.addEventListener("click",function(){setGenre("")});var LIVE_ZONES=".played-header, .played-hero, .played-controls, .played-podium, .played-list, .played-filtered-empty";modal.addEventListener("click",function(e){if(!e.target.closest(LIVE_ZONES))closeModal()});document.addEventListener("keydown",function(e){if(e.key==="Escape"&&modal.classList.contains("is-open")){closeModal();e.preventDefault()}});inited=true}window.openMostPlayedModal=openModal;window.closeMostPlayedModal=closeModal;function boot(){init();if(/[?&]open=played\b/.test(location.search))openModal()}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",boot)}else{boot()}})();
